var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어때요, 스승님. 제 말대로죠?","JPN":"どうですか、師匠。僕の言うとおりでしたね？","ENG":"What did I tell you, Master? I was right, huh?","TWN":"師父你看，我說的沒錯吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……운이 좋았다고 해 두지.","JPN":"……運が良かったということにしておこう。","ENG":"…You got lucky.","TWN":"……算你運氣好。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그나저나……. 루크레시아 님이라고 했던가요?","JPN":"ところで……ルクレシアさんとおっしゃいましたか？","ENG":"Anyway… Lady Lucrecia, was it?","TWN":"那個……你是叫露可蕾西亞嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"조금 억울하네요. 그런 식으로 이쪽에 책임을 떠넘기면 곤란합니다.","JPN":"少し気分が悪いですね。そうやってこちらに全責任を押し付けるのは困ります。","ENG":"Don't you think you're being a tad unfair? You can't just blame me for everything.","TWN":"你這樣說有點不公平喔，怎麼可以把責任推給我們呢？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"상호 합의를 먼저 어긴 것도, 제 시정 요구를 무시한 것도 그쪽일 텐데요?","JPN":"相互合意を先に破ったのも、是正要求を無視したのもそちらだと思いますが。","ENG":"You folks were the first to break our mutual agreement and disregard my request to take corrective action… weren't you?","TWN":"違反雙方協議，對於我提出的改正需求也不予理會的可是你們喔！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 일은 저도 유감이에요. 클라레스 전하께서 말씀을 거칠게 하신 건 사실이죠.","JPN":"その件は私も残念に思っています。クラレス殿下が少々言い過ぎたのは事実です。","ENG":"I too find that most regrettable. 'Tis true His Highness Prince Clareth spoke rather uncouthly with thee.","TWN":"對於那件事我深表遺憾，克拉雷斯殿下的發言確實有失身分。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 이유가 무엇이든, 저희의 뜻에 거스르는 것은 용납할 수 없습니다.","JPN":"しかし理由が何であれ、私たちの意思に逆らう行為は容認できません。","ENG":"But regardless of the reason, we shall not accept any defiance of our will.","TWN":"但無論理由是什麼，我們都絕對不接受抗命。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저런, 멋대로 남의 세계에 넘어와서는 원래 살던 사람들을 이방인이라고 부르다니. ","JPN":"おや、勝手に他人の世界に渡ってきて、元々住んでいた人たちのことを異邦人と呼ぶなんて。","ENG":"My, my. How can you call us outsiders when you're the ones squatting in our world? ","TWN":"哎呀～擅自侵犯別人的世界，還把原本住在那裡的人稱為外邦人，"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"안타깝게도 정신 상태가 그리 온전치 못하신가 보네요.","JPN":"残念ながら精神状態がまともではないようですね。","ENG":"Sadly, it seems y'all are not quite right in the head.","TWN":"可憐喔～看來你病得不輕呢！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……뭐라고요?","JPN":"……なんですって？","ENG":"…What did you say?","TWN":"……你說什麼？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아, 너무 돌려 말해서 이해하시기 어려운 모양이군요. 쉽게 말씀드리죠.","JPN":"ああ、言い回しが難しくて理解できなかったようですね。シンプルに申し上げます。","ENG":"Oh, perhaps I've beat around the bush too much for you to understand. Let me put it bluntly, then.","TWN":"我講得太拐彎抹角你聽不懂嗎？那我就說白話文吧！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"헛소리 집어치우고 당장 주시윤 군을 풀어주지 않으면 당신은 이곳에서 죽는다는 뜻입니다.","JPN":"ふざけたことを抜かすのは辞めて今すぐアキヤマ君を解放しなければ、あなたはここで死ぬという意味です。","ENG":"If you don't shut up and release Joo Shiyoon at once, you're going to die here.","TWN":"少在那邊跟我廢話那麼多，現在就給我立刻放了周時雲，否則這裡就是你的葬身之地！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"존경하는 성녀님.","JPN":"尊敬する聖女様。","ENG":"Your venerable Saintess.","TWN":"尊敬的聖女大人，這樣有聽懂嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석, 못 보던 사이에 성격이 좀 변했군.","JPN":"あいつ、見ない間に性格がちょっと変わったな。","ENG":"He's changed a bit since I last saw him.","TWN":"看來那傢伙在這段時間個性又變了不少。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"꼭 그렇지만은 않습니다.","JPN":"別にそうでもありません。","ENG":"Not really.","TWN":"不是這樣的。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님은 모르시겠지만 예전에도 어떤 면에서는 저 이상으로 과격한 면이 있었죠.","JPN":"師匠は知らないと思いますが、昔からある意味私以上に過激なところがありましたよ。","ENG":"You might not have known this, but he's always had that aggressive side to him in some ways.","TWN":"師父你可能不太清楚，但他從以前會因為某些事而失控，甚至比你剛看到的還要誇張。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"가, 감히 그 따위 말을……!","JPN":"よ、よくもそんなことを……！","ENG":"H-how dare you!","TWN":"大…大膽，竟然如此口無遮攔……！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};